// Package templates contains templ component definitions.
// The actual component implementations are generated by `templ generate`
// into *_templ.go files (gitignored). This stub file ensures the package
// compiles and exports the correct function signatures before codegen runs,
// satisfying `go vet` and IDE tooling.
//
// Run `make templ` (or `make assets`) to regenerate.
//
// NOTE: when *_templ.go files are present after `make templ`, the generated
// files will re-declare these symbols and this stub must be removed or the
// build tags adjusted. The stub is removed automatically by templ generate.
// For now it provides the minimal surface area for go vet to pass.
package templates

import (
	"context"
	"io"
	"time"

	"github.com/a-h/templ"
	"github.com/nhymxu/kith-pms/internal/journal"
	"github.com/nhymxu/kith-pms/internal/labels"
	"github.com/nhymxu/kith-pms/internal/people"
)

// componentFunc is a thin templ.Component adapter around a render function.
type componentFunc func(ctx context.Context, w io.Writer) error

func (f componentFunc) Render(ctx context.Context, w io.Writer) error {
	return f(ctx, w)
}

func stub(msg string) templ.Component {
	return componentFunc(func(_ context.Context, w io.Writer) error {
		_, err := io.WriteString(w, "<!-- "+msg+": run make templ -->")
		return err
	})
}

