// dobValue formats a nullable *time.Time as YYYY-MM-DD for <input type="date">.
// Declared here so handlers can call it; real implementation lives in people_form.templ.
func dobValue(t *time.Time) string {
	if t == nil {
		return ""
	}
	return t.Format("2006-01-02")
}

